/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `stock_compuestos` AS select `pc`.`id` AS `producto_compuesto_id`,`pc`.`sku` AS `sku`,`pc`.`nombre` AS `nombre`,`pc`.`precio_base` AS `precio_base`,min(floor((`pb`.`stock_actual` / `c`.`cantidad_necesaria`))) AS `stock_disponible`,group_concat(concat(`pb`.`sku`,':',`pb`.`stock_actual`,'/',`c`.`cantidad_necesaria`) order by `pb`.`sku` ASC separator ' | ') AS `componentes_detalle` from ((`productos_compuestos` `pc` join `componentes` `c` on((`pc`.`id` = `c`.`producto_compuesto_id`))) join `productos_base` `pb` on((`c`.`producto_base_id` = `pb`.`id`))) group by `pc`.`id`,`pc`.`sku`,`pc`.`nombre`,`pc`.`precio_base` */;
